#include<bits/stdc++.h>
using namespace std;
int t, n, x, y;
bool a[10101],b[10101];
int main() {
	cin >> t;
	while (t--) {
		cin >> n;
		for (int i = 1; i <= n; i++) {
			cin >> a[i];
		}
		for (int i = 1; i <= n; i++) {
			cin >> b[i];
		}
        x=0;
        y=0;
		for (int i = 1; i <= n; i++) {
			if (a[i]==1 && b[i]==0) x++;
            if (b[i]==1 && a[i]==0) y++;
		}

        if((x+y)%2==1) {cout<<-1<<"\n";}
        else cout<<x/2+y/2+(x%2)*2<<"\n";
	}
	return 0;
}
